index.js.content:
import "dotenv/config";
import { run } from "@grammyjs/runner";
import { envHealth } from "./lib/config.js";
import { log, safeErr } from "./lib/logger.js";

process.on("unhandledRejection", (reason) => {
  log.error("unhandled rejection", { err: safeErr(reason) });
  process.exit(1);
});

process.on("uncaughtException", (err) => {
  log.error("uncaught exception", { err: safeErr(err) });
  process.exit(1);
});

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function boot() {
  log.info("boot start");
  try {
    const { cfg } = await import("./lib/config.js");
    const { createBot } = await import("./bot.js");
    const { registerCommands } = await import("./commands/loader.js");
    const { startScheduler, stopScheduler } = await import("./services/scheduler.js");

    log.info("config loaded", envHealth());

    if (!cfg.TELEGRAM_BOT_TOKEN) {
      console.error("TELEGRAM_BOT_TOKEN is required. Add it in your CookMyBots Config tab or .env file, then redeploy.");
      process.exit(1);
    }

    if (!cfg.MONGODB_URI) {
      log.warn("MONGODB_URI missing; using temporary in-memory storage. Data will reset on restart.");
    }

    if (!cfg.COOKMYBOTS_X_ENDPOINT || !cfg.COOKMYBOTS_X_KEY) {
      log.warn("X integration disabled until COOKMYBOTS_X_ENDPOINT and COOKMYBOTS_X_KEY are set and an X account is connected in CookMyBots.");
    }

    const bot = createBot(cfg.TELEGRAM_BOT_TOKEN);
    await registerCommands(bot);

    await bot.init();
    await bot.api.setMyCommands([
      { command: "start", description: "Welcome and setup guidance" },
      { command: "help", description: "Show available commands" },
      { command: "setup", description: "Initialize a group" },
      { command: "addtoken", description: "Add a token to track" },
      { command: "removetoken", description: "Remove a tracked token" },
      { command: "tokens", description: "List tracked tokens" },
      { command: "price", description: "Show current token price" },
      { command: "trend", description: "Show token trend summary" },
      { command: "digest", description: "Generate on-demand digest" },
      { command: "announcements", description: "Show recent official X posts" },
      { command: "settime", description: "Set daily digest time" },
      { command: "settimezone", description: "Set digest timezone" },
      { command: "alerts", description: "Toggle immediate alerts" },
      { command: "pause", description: "Pause scheduled posts" },
      { command: "resume", description: "Resume scheduled posts" },
      { command: "settings", description: "Show group settings" },
      { command: "reset", description: "Clear your bot memory" },
    ]);

    let backoff = 2000;
    let runner = null;
    startScheduler(bot);

    while (true) {
      try {
        log.info("polling loop start", { loop: "telegram" });
        await bot.api.deleteWebhook({ drop_pending_updates: true });
        runner = run(bot, {
          runner: {
            fetch: { allowed_updates: ["message", "callback_query"] },
            sink: { concurrency: 1 },
          },
        });
        log.info("polling started", { loop: "telegram" });
        await runner.task();
        backoff = 2000;
      } catch (err) {
        log.error("polling failure", { loop: "telegram", err: safeErr(err), backoffMs: backoff });
        try {
          if (runner?.isRunning?.()) await runner.stop();
        } catch (stopErr) {
          log.warn("runner stop failed", { err: safeErr(stopErr) });
        }
        await sleep(backoff);
        backoff = Math.min(backoff * 2, 20000);
      }
    }
  } catch (err) {
    log.error("boot failure", { code: err?.code, err: safeErr(err) });
    if (err?.code === "ERR_MODULE_NOT_FOUND") {
      console.error("A module could not be loaded. Check that all relative imports include .js and the files exist.");
    }
    process.exit(1);
  }
}

boot();

admin.js.content:
export async function isGroupAdmin(ctx) {
  if (!ctx.chat || ctx.chat.type === "private") return true;
  const userId = ctx.from?.id;
  if (!userId) return false;
  try {
    const member = await ctx.api.getChatMember(ctx.chat.id, userId);
    return member.status === "creator" || member.status === "administrator";
  } catch {
    return false;
  }
}

export async function requireAdmin(ctx) {
  if (await isGroupAdmin(ctx)) return true;
  await ctx.reply("Only group admins can change MemePulse settings.");
  return false;
}

ai.js.content:
import { cfg } from "./config.js";
import { BOT_PROFILE } from "./botProfile.js";
import { log, safeErr } from "./logger.js";

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function timeoutSignal(ms) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), ms);
  return { signal: controller.signal, clear: () => clearTimeout(timer) };
}

async function readJson(res) {
  const text = await res.text();
  try {
    return { json: JSON.parse(text), text };
  } catch {
    return { json: null, text };
  }
}

function configured() {
  return Boolean(cfg.COOKMYBOTS_AI_ENDPOINT && cfg.COOKMYBOTS_AI_KEY);
}

export async function aiChat(messages, meta = {}) {
  if (!configured()) {
    return { ok: false, error: "AI gateway is not configured." };
  }

  const body = {
    messages: [
      { role: "system", content: BOT_PROFILE },
      ...messages,
    ].slice(0, 18),
    meta: { platform: "telegram", ...meta },
  };

  const retries = Number.isFinite(cfg.AI_MAX_RETRIES) ? cfg.AI_MAX_RETRIES : 2;
  for (let attempt = 0; attempt <= retries; attempt += 1) {
    const t = timeoutSignal(cfg.AI_TIMEOUT_MS || 600000);
    const started = Date.now();
    try {
      log.info("ai call start", { feature: "chat", platform: "telegram", attempt });
      const res = await fetch(`${cfg.COOKMYBOTS_AI_ENDPOINT}/chat`, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${cfg.COOKMYBOTS_AI_KEY}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify(body),
        signal: t.signal,
      });
      const { json, text } = await readJson(res);
      if (!res.ok) throw new Error(json?.error?.message || json?.message || text || `AI HTTP ${res.status}`);
      const content = String(json?.output?.content || "").trim();
      log.info("ai call success", { feature: "chat", platform: "telegram", ms: Date.now() - started });
      return { ok: true, content, json };
    } catch (err) {
      log.error("ai call failure", { feature: "chat", platform: "telegram", attempt, err: safeErr(err) });
      if (attempt >= retries) return { ok: false, error: safeErr(err) };
      await sleep(750 * (attempt + 1));
    } finally {
      t.clear();
    }
  }
  return { ok: false, error: "AI failed." };
}

export async function aiChainGpt(question, meta = {}) {
  if (!configured()) {
    return { ok: false, error: "AI gateway is not configured." };
  }

  const t = timeoutSignal(cfg.AI_TIMEOUT_MS || 600000);
  const started = Date.now();
  try {
    log.info("ai call start", { feature: "chaingpt", platform: "telegram" });
    const res = await fetch(`${cfg.COOKMYBOTS_AI_ENDPOINT}/chaingpt/chat`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${cfg.COOKMYBOTS_AI_KEY}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        mode: "web3",
        question: `${BOT_PROFILE}\n\nUser request:\n${String(question || "").slice(0, 8000)}`,
        meta: { platform: "telegram", ...meta },
      }),
      signal: t.signal,
    });
    const { json, text } = await readJson(res);
    if (!res.ok) throw new Error(json?.error?.message || json?.message || text || `AI HTTP ${res.status}`);
    const content = String(json?.output?.content || json?.output?.message || "").trim();
    log.info("ai call success", { feature: "chaingpt", platform: "telegram", ms: Date.now() - started });
    return { ok: true, content, json };
  } catch (err) {
    log.error("ai call failure", { feature: "chaingpt", platform: "telegram", err: safeErr(err) });
    return { ok: false, error: safeErr(err) };
  } finally {
    t.clear();
  }
}

export async function aiSmartChat(_unusedCfg, userText, opts = {}) {
  if (cfg.WEB3_CHAT_MODE === "off") {
    const messages = [
      { role: "system", content: opts.system || "Answer clearly and briefly." },
      { role: "user", content: String(userText || "") },
    ];
    const result = await aiChat(messages, opts.meta || {});
    return { ok: result.ok, json: { output: { content: result.content || "" } }, text: result.content || "", error: result.error };
  }
  const result = await aiChainGpt(userText, opts.meta || {});
  return { ok: result.ok, json: { output: { content: result.content || "" } }, text: result.content || "", error: result.error };
}

