export function buildBotProfile() {
  return [
    "Bot Profile: MemePulse Watcher is a Telegram group bot for memecoin and token communities. It tracks selected tokens, posts daily market digests, shows compact price and trend summaries, and can detect important official X announcements when the CookMyBots X Proxy is configured.",
    "Public commands: /start welcomes users, /help lists usage, /setup initializes a group, /addtoken adds a token, /removetoken removes a token, /tokens lists tracked tokens, /price shows live market data, /trend shows movement signals, /digest generates an on-demand digest, /announcements shows recent detected X posts, /settime sets digest time, /settimezone sets timezone, /alerts toggles immediate alerts, /pause pauses delivery, /resume resumes delivery, /settings shows configuration, /reset clears user memory.",
    "Key rules: admin-only commands require Telegram group admin permissions. Group notifications are informational only and are not financial advice. X data uses the CookMyBots X Proxy only; users must connect an X account in the CookMyBots UI for OAuth-backed access. If MongoDB is missing, the bot runs with temporary in-memory storage and warns in logs.",
  ].join("\n");
}

export const BOT_PROFILE = buildBotProfile();
export const BOT_PROMPT = BOT_PROFILE;

db.js.content:
import { MongoClient } from "mongodb";
import { cfg } from "./config.js";
import { log, safeErr } from "./logger.js";

let client = null;
let db = null;
let indexesReady = false;

export async function getDb() {
  if (!cfg.MONGODB_URI) return null;
  if (db) return db;

  try {
    client = new MongoClient(cfg.MONGODB_URI, { maxPoolSize: 8, ignoreUndefined: true });
    await client.connect();
    db = client.db();
    log.info("db connected", { mongoSet: true });
    await ensureIndexes(db);
    return db;
  } catch (err) {
    log.error("db connect failed", { err: safeErr(err) });
    db = null;
    return null;
  }
}

export async function ensureIndexes(database) {
  if (!database || indexesReady) return;
  try {
    await database.collection("users").createIndex({ platform: 1, userId: 1 }, { unique: true });
    await database.collection("groups").createIndex({ chatId: 1 }, { unique: true });
    await database.collection("tokens").createIndex({ symbol: 1 });
    await database.collection("tokens").createIndex({ contractAddress: 1 });
    await database.collection("subscriptions").createIndex({ chatId: 1, symbol: 1 }, { unique: true });
    await database.collection("subscriptions").createIndex({ status: 1, nextDigestAt: 1 });
    await database.collection("marketsnapshots").createIndex({ symbol: 1, ts: -1 });
    await database.collection("xposts").createIndex({ postId: 1 }, { unique: true });
    await database.collection("xposts").createIndex({ symbol: 1, createdAt: -1 });
    await database.collection("digestruns").createIndex({ dedupeKey: 1 }, { unique: true });
    await database.collection("auditlogs").createIndex({ ts: -1 });
    await database.collection("memory_messages").createIndex({ platform: 1, userId: 1, chatId: 1, ts: -1 });
    await database.collection("x_cursors").createIndex({ handle: 1 }, { unique: true });
    indexesReady = true;
    log.info("db indexes ready");
  } catch (err) {
    log.error("db indexes failed", { collection: "multiple", operation: "createIndex", err: safeErr(err) });
  }
}

export async function collection(name) {
  const database = await getDb();
  return database ? database.collection(name) : null;
}

export async function closeDb() {
  if (client) await client.close();
  client = null;
  db = null;
}

logger.js.content:
export function safeErr(err) {
  return (
    err?.response?.data?.error?.message ||
    err?.response?.data?.message ||
    err?.message ||
    String(err)
  );
}

function write(level, msg, meta = {}) {
  const clean = { ...meta };
  delete clean.token;
  delete clean.key;
  delete clean.authorization;
  const line = JSON.stringify({ level, msg, ts: new Date().toISOString(), ...clean });
  if (level === "error") console.error(line);
  else if (level === "warn") console.warn(line);
  else console.log(line);
}

export const log = {
  info: (msg, meta) => write("info", msg, meta),
  warn: (msg, meta) => write("warn", msg, meta),
  error: (msg, meta) => write("error", msg, meta),
};

