import { aiChainGpt } from "../lib/ai.js";
import { getMarketSnapshot } from "./marketProvider.js";
import { getRecentXPosts, getToken, normalizeSymbol } from "./store.js";

function money(value) {
  const n = Number(value || 0);
  if (!Number.isFinite(n)) return "n/a";
  if (n >= 1_000_000_000) return `$${(n / 1_000_000_000).toFixed(2)}B`;
  if (n >= 1_000_000) return `$${(n / 1_000_000).toFixed(2)}M`;
  if (n >= 1_000) return `$${(n / 1_000).toFixed(2)}K`;
  if (n > 0 && n < 0.01) return `$${n.toPrecision(4)}`;
  return `$${n.toFixed(4)}`;
}

function pct(value) {
  const n = Number(value || 0);
  const sign = n > 0 ? "+" : "";
  return `${sign}${n.toFixed(2)}%`;
}

export function formatPrice(snapshot) {
  return [
    `${snapshot.symbol} price`,
    `Price: ${money(snapshot.priceUsd)}`,
    `24h move: ${pct(snapshot.change24hPct)}`,
    `24h volume: ${money(snapshot.volume24hUsd)}`,
    `Market cap: ${money(snapshot.marketCapUsd)}`,
    `Source: ${snapshot.source}, updated ${snapshot.sourceUpdatedAt.toISOString()}`,
    "Informational only, not financial advice.",
  ].join("\n");
}

export function formatTrend(snapshot) {
  const change = Number(snapshot.change24hPct || 0);
  const direction = change > 3 ? "uptrend" : change < -3 ? "downtrend" : "mostly sideways";
  const volume = Number(snapshot.volume24hUsd || 0) > 0 ? `Volume is ${money(snapshot.volume24hUsd)} over 24h.` : "Volume data is unavailable.";
  return [
    `${snapshot.symbol} trend`,
    `Signal: ${direction}`,
    `24h move: ${pct(change)}`,
    volume,
    `Market cap: ${money(snapshot.marketCapUsd)}`,
    `Data source timestamp: ${snapshot.sourceUpdatedAt.toISOString()}`,
    "Informational only, not financial advice.",
  ].join("\n");
}

export async function buildDigest(symbol) {
  const s = normalizeSymbol(symbol);
  const snapshot = await getMarketSnapshot(s);
  const token = await getToken(s);
  const posts = await getRecentXPosts(s, 3);
  const base = [
    `${s} daily digest`,
    `Price: ${money(snapshot.priceUsd)} (${pct(snapshot.change24hPct)} 24h)`,
    `Volume: ${money(snapshot.volume24hUsd)}`,
    `Market cap: ${money(snapshot.marketCapUsd)}`,
    posts.length ? "Recent announcements:" : "Recent announcements: none detected yet.",
    ...posts.map((p) => `${p.classification}: ${p.text.slice(0, 180)} ${p.url}`),
  ].join("\n");

  const ai = await aiChainGpt(
    `Create a concise Telegram daily token digest for ${s}. Do not give financial advice. Use this data only:\n${base}`,
    { feature: "digest", symbol: s }
  );

  const summary = ai.ok && ai.content ? ai.content : base;
  return `${summary}\n\nSource: CoinGecko${token?.officialXHandles?.length ? " and configured official X handles" : ""}. Informational only, not financial advice.`;
}

export async function buildPrice(symbol) {
  return formatPrice(await getMarketSnapshot(symbol));
}

export async function buildTrend(symbol) {
  return formatTrend(await getMarketSnapshot(symbol));
}

export function formatAnnouncements(symbol, posts) {
  const s = normalizeSymbol(symbol);
  if (!posts.length) return `No recent official X announcements found for ${s}. Add an official handle with /addtoken ${s} x=handle and make sure the CookMyBots X Proxy is configured.`;
  return [`Recent ${s} announcements`, ...posts.map((p) => `${p.classification}: ${p.text.slice(0, 240)}\n${p.url}`)].join("\n\n");
}

marketProvider.js.content:
import { cfg } from "../lib/config.js";
import { log, safeErr } from "../lib/logger.js";
import { getToken, normalizeSymbol, saveSnapshot, upsertToken } from "./store.js";

const cache = new Map();
const CACHE_MS = 60000;
const MAX_CACHE = 500;

function cacheGet(key) {
  const hit = cache.get(key);
  if (!hit || Date.now() - hit.ts > CACHE_MS) return null;
  return hit.value;
}

function cacheSet(key, value) {
  cache.set(key, { ts: Date.now(), value });
  while (cache.size > MAX_CACHE) cache.delete(cache.keys().next().value);
}

async function fetchJson(url) {
  const cached = cacheGet(url);
  if (cached) return cached;
  const started = Date.now();
  try {
    log.info("provider call start", { provider: "coingecko", url: url.replace(/\?.*/, "") });
    const res = await fetch(url, { headers: { accept: "application/json" } });
    const json = await res.json().catch(() => null);
    if (!res.ok) throw new Error(json?.error || `HTTP ${res.status}`);
    log.info("provider call success", { provider: "coingecko", ms: Date.now() - started });
    cacheSet(url, json);
    return json;
  } catch (err) {
    log.error("provider call failure", { provider: "coingecko", err: safeErr(err) });
    throw err;
  }
}

function parseHandles(args) {
  const handles = [];
  const keywords = [];
  for (const part of args) {
    if (part.startsWith("x=")) {
      handles.push(...part.slice(2).split(",").map((x) => x.replace(/^@/, "").trim()).filter(Boolean));
    }
    if (part.startsWith("keywords=")) {
      keywords.push(...part.slice(9).split(",").map((x) => x.trim()).filter(Boolean));
    }
  }
  return { handles: [...new Set(handles)], keywords: [...new Set(keywords)] };
}

export async function resolveToken(input, extraArgs = []) {
  const query = String(input || "").trim();
  const symbol = normalizeSymbol(query);
  const existing = await getToken(symbol);
  const { handles, keywords } = parseHandles(extraArgs);
  if (existing && !handles.length && !keywords.length) return existing;

  let token = {
    symbol,
    name: symbol,
    coingeckoId: existing?.coingeckoId || "",
    contractAddress: query.startsWith("0x") ? query : existing?.contractAddress || "",
    officialXHandles: handles.length ? handles : existing?.officialXHandles || [],
    trackingKeywords: keywords.length ? keywords : existing?.trackingKeywords || [symbol],
  };

  try {
    if (query.startsWith("0x")) {
      const data = await fetchJson(`${cfg.COINGECKO_API_BASE}/coins/ethereum/contract/${encodeURIComponent(query)}`);
      token = {
        ...token,
        symbol: normalizeSymbol(data?.symbol || symbol),
        name: data?.name || token.name,
        coingeckoId: data?.id || token.coingeckoId,
        contractAddress: query,
      };
    } else if (!token.coingeckoId) {
      const data = await fetchJson(`${cfg.COINGECKO_API_BASE}/search?query=${encodeURIComponent(query)}`);
      const coin = Array.isArray(data?.coins) ? data.coins.find((c) => normalizeSymbol(c.symbol) === symbol) || data.coins[0] : null;
      if (coin) {
        token = { ...token, symbol: normalizeSymbol(coin.symbol || symbol), name: coin.name || token.name, coingeckoId: coin.id || "" };
      }
    }
  } catch {
    log.warn("token resolve degraded", { symbol });
  }

  return upsertToken(token);
}

export async function getMarketSnapshot(symbol) {
  const s = normalizeSymbol(symbol);
  const token = await getToken(s);
  if (!token?.coingeckoId) {
    throw new Error(`No market provider ID found for ${s}. Try /addtoken ${s} first.`);
  }

  const ids = encodeURIComponent(token.coingeckoId);
  const data = await fetchJson(`${cfg.COINGECKO_API_BASE}/simple/price?ids=${ids}&vs_currencies=usd&include_market_cap=true&include_24hr_vol=true&include_24hr_change=true&include_last_updated_at=true`);
  const row = data?.[token.coingeckoId] || {};
  const snapshot = {
    symbol: token.symbol,
    tokenId: token.coingeckoId,
    priceUsd: Number(row.usd || 0),
    change24hPct: Number(row.usd_24h_change || 0),
    volume24hUsd: Number(row.usd_24h_vol || 0),
    marketCapUsd: Number(row.usd_market_cap || 0),
    liquidityUsd: null,
    holderCount: null,
    source: "coingecko",
    sourceUpdatedAt: row.last_updated_at ? new Date(Number(row.last_updated_at) * 1000) : new Date(),
    ts: new Date(),
  };
  await saveSnapshot(snapshot);
  return snapshot;
}

scheduler.js.content:
import { cfg } from "../lib/config.js";
import { log, safeErr } from "../lib/logger.js";
import { sendText } from "./dispatcher.js";
import { buildDigest } from "./insights.js";
import { fetchRecentAnnouncements } from "./xProvider.js";
import { getActiveSubscriptions, getGroup, getToken, saveDigestRun, saveXPost } from "./store.js";

let running = false;
let announcementLastRun = 0;
let cycles = 0;

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function localParts(date, timeZone) {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  }).formatToParts(date);
  const obj = Object.fromEntries(parts.map((p) => [p.type, p.value]));
  return { date: `${obj.year}-${obj.month}-${obj.day}`, time: `${obj.hour}:${obj.minute}` };
}

async function runDigestCycle(bot) {
  const subs = await getActiveSubscriptions();
  for (const sub of subs) {
    const group = await getGroup(sub.chatId);
    if (group?.enabled === false) continue;
    const tz = sub.timezone || group?.timezone || cfg.DEFAULT_TIMEZONE;
    const digestTime = sub.digestTime || group?.defaultDigestTime || cfg.DEFAULT_DIGEST_TIME;
    const now = localParts(new Date(), tz);
    if (now.time !== digestTime) continue;

    const dedupeKey = `${sub.chatId}:${sub.symbol}:${now.date}`;
    const inserted = await saveDigestRun({
      dedupeKey,
      chatId: sub.chatId,
      symbol: sub.symbol,
      period: now.date,
      sendStatus: "started",
    });
    if (!inserted) continue;

    try {
      const text = await buildDigest(sub.symbol);
      const ok = await sendText(bot, sub.chatId, text);
      await saveDigestRun({ dedupeKey, chatId: sub.chatId, symbol: sub.symbol, period: now.date, summary: text, sendStatus: ok ? "sent" : "failed" });
      log.info("digest cycle sent", { chatId: sub.chatId, symbol: sub.symbol, dedupeKey });
    } catch (err) {
      await saveDigestRun({ dedupeKey, chatId: sub.chatId, symbol: sub.symbol, period: now.date, sendStatus: "failed", error: safeErr(err) });
      log.error("digest cycle failure", { chatId: sub.chatId, symbol: sub.symbol, err: safeErr(err) });
    }
  }
}

async function runAnnouncementCycle(bot) {
  const subs = await getActiveSubscriptions();
  for (const sub of subs) {
    if (!sub.alertsImmediate) continue;
    const token = await getToken(sub.symbol);
    const handles = token?.officialXHandles || [];
    for (const handle of handles) {
      const res = await fetchRecentAnnouncements(handle, { limit: 10 });
      if (!res.ok) continue;
      for (const post of res.posts.filter((p) => p.severity === "high")) {
        const fresh = await saveXPost({ ...post, symbol: sub.symbol, deliveredStatus: "pending" });
        if (!fresh) continue;
        const text = [`Major ${sub.symbol} announcement signal`, `${post.text.slice(0, 500)}`, post.url, "Source: configured official X handle. Informational only."].join("\n");
        const sent = await sendText(bot, sub.chatId, text);
        await saveXPost({ ...post, symbol: sub.symbol, deliveredStatus: sent ? "sent" : "failed" });
      }
    }
  }
}

export function startScheduler(bot) {
  if (running) return;
  running = true;
  log.info("polling loop start", { loop: "scheduler", pollMs: cfg.SCHEDULER_POLL_MS });

  (async () => {
    while (running) {
      try {
        cycles += 1;
        log.info("polling cycle run", { loop: "scheduler", cycle: cycles });
        await runDigestCycle(bot);
        if (Date.now() - announcementLastRun >= cfg.ANNOUNCEMENT_POLL_MS) {
          announcementLastRun = Date.now();
          await runAnnouncementCycle(bot);
        }
        if (cycles % 1 === 0) {
          const m = process.memoryUsage();
          log.info("mem", { rssMB: Math.round(m.rss / 1e6), heapUsedMB: Math.round(m.heapUsed / 1e6) });
        }
      } catch (err) {
        log.error("polling cycle failure", { loop: "scheduler", err: safeErr(err) });
      }
      await sleep(Math.max(10000, cfg.SCHEDULER_POLL_MS));
    }
  })();
}

export function stopScheduler() {
  running = false;
}

store.js.content:
import { collection } from "../lib/db.js";
import { cfg } from "../lib/config.js";
import { log, safeErr } from "../lib/logger.js";

const mem = {
  users: new Map(),
  groups: new Map(),
  tokens: new Map(),
  subscriptions: new Map(),
  marketsnapshots: [],
  xposts: new Map(),
  digestruns: new Map(),
  auditlogs: [],
  x_cursors: new Map(),
};

function subKey(chatId, symbol) {
  return `${String(chatId)}:${String(symbol).toUpperCase()}`;
}

function cleanMutable(obj) {
  const out = { ...obj };
  delete out._id;
  delete out.createdAt;
  return out;
}

export function normalizeSymbol(value) {
  return String(value || "").trim().replace(/^\$/, "").toUpperCase().slice(0, 32);
}

export async function audit(action, data = {}) {
  const doc = { action, data, ts: new Date() };
  const col = await collection("auditlogs");
  if (!col) {
    mem.auditlogs.push(doc);
    if (mem.auditlogs.length > 1000) mem.auditlogs.shift();
    return;
  }
  try {
    await col.insertOne(doc);
  } catch (err) {
    log.error("db write failed", { collection: "auditlogs", operation: "insertOne", err: safeErr(err) });
  }
}

export async function upsertUser(ctx) {
  const userId = String(ctx.from?.id || "");
  if (!userId) return;
  const doc = cleanMutable({
    platform: "telegram",
    userId,
    username: ctx.from?.username || "",
    firstName: ctx.from?.first_name || "",
    lastName: ctx.from?.last_name || "",
    updatedAt: new Date(),
  });
  const col = await collection("users");
  if (!col) {
    mem.users.set(userId, { ...(mem.users.get(userId) || { createdAt: new Date() }), ...doc });
    return;
  }
  try {
    await col.updateOne(
      { platform: "telegram", userId },
      { $setOnInsert: { createdAt: new Date() }, $set: doc },
      { upsert: true }
    );
  } catch (err) {
    log.error("db write failed", { collection: "users", operation: "updateOne", err: safeErr(err) });
  }
}

export async function upsertGroup(ctx, patch = {}) {
  const chatId = String(ctx.chat?.id || patch.chatId || "");
  if (!chatId) return null;
  const doc = cleanMutable({
    chatId,
    title: ctx.chat?.title || patch.title || "Private chat",
    type: ctx.chat?.type || patch.type || "private",
    timezone: patch.timezone || cfg.DEFAULT_TIMEZONE,
    defaultDigestTime: patch.defaultDigestTime || cfg.DEFAULT_DIGEST_TIME,
    language: patch.language || "en",
    enabled: patch.enabled ?? true,
    adminConfigured: patch.adminConfigured ?? false,
    updatedAt: new Date(),
  });
  const col = await collection("groups");
  if (!col) {
    const existing = mem.groups.get(chatId) || { createdAt: new Date() };
    const next = { ...doc, ...existing, ...patch, updatedAt: new Date() };
    mem.groups.set(chatId, next);
    return next;
  }
  try {
    await col.updateOne({ chatId }, { $setOnInsert: { createdAt: new Date() }, $set: doc }, { upsert: true });
    return await col.findOne({ chatId });
  } catch (err) {
    log.error("db write failed", { collection: "groups", operation: "updateOne", err: safeErr(err) });
    return null;
  }
}

export async function getGroup(chatId) {
  const id = String(chatId);
  const col = await collection("groups");
  if (!col) return mem.groups.get(id) || null;
  try {
    return await col.findOne({ chatId: id });
  } catch (err) {
    log.error("db read failed", { collection: "groups", operation: "findOne", err: safeErr(err) });
    return null;
  }
}

export async function updateGroup(chatId, patch) {
  const id = String(chatId);
  const doc = cleanMutable({ ...patch, updatedAt: new Date() });
  const col = await collection("groups");
  if (!col) {
    const existing = mem.groups.get(id) || { chatId: id, timezone: cfg.DEFAULT_TIMEZONE, defaultDigestTime: cfg.DEFAULT_DIGEST_TIME, createdAt: new Date() };
    mem.groups.set(id, { ...existing, ...doc });
    return mem.groups.get(id);
  }
  try {
    await col.updateOne({ chatId: id }, { $setOnInsert: { createdAt: new Date() }, $set: doc }, { upsert: true });
    return await col.findOne({ chatId: id });
  } catch (err) {
    log.error("db write failed", { collection: "groups", operation: "updateOne", err: safeErr(err) });
    return null;
  }
}

export async function upsertToken(token) {
  const symbol = normalizeSymbol(token.symbol || token.query);
  const doc = cleanMutable({
    symbol,
    name: token.name || symbol,
    chain: token.chain || "",
    contractAddress: token.contractAddress || "",
    coingeckoId: token.coingeckoId || "",
    officialXHandles: Array.isArray(token.officialXHandles) ? token.officialXHandles : [],
    trackingKeywords: Array.isArray(token.trackingKeywords) ? token.trackingKeywords : [symbol],
    verificationStatus: token.verificationStatus || "user_configured",
    updatedAt: new Date(),
  });
  const col = await collection("tokens");
  if (!col) {
    mem.tokens.set(symbol, { ...(mem.tokens.get(symbol) || { createdAt: new Date() }), ...doc });
    return mem.tokens.get(symbol);
  }
  try {
    await col.updateOne({ symbol }, { $setOnInsert: { createdAt: new Date() }, $set: doc }, { upsert: true });
    return await col.findOne({ symbol });
  } catch (err) {
    log.error("db write failed", { collection: "tokens", operation: "updateOne", err: safeErr(err) });
    return null;
  }
}

export async function getToken(symbol) {
  const s = normalizeSymbol(symbol);
  const col = await collection("tokens");
  if (!col) return mem.tokens.get(s) || null;
  try {
    return await col.findOne({ symbol: s });
  } catch (err) {
    log.error("db read failed", { collection: "tokens", operation: "findOne", err: safeErr(err) });
    return null;
  }
}

export async function upsertSubscription(chatId, symbol, patch = {}) {
  const id = String(chatId);
  const s = normalizeSymbol(symbol);
  const doc = cleanMutable({
    chatId: id,
    symbol: s,
    status: patch.status || "active",
    alertsImmediate: patch.alertsImmediate ?? true,
    trendThresholdPct: Number(patch.trendThresholdPct || 10),
    enabledMetrics: patch.enabledMetrics || ["price", "volume", "marketCap", "announcements"],
    digestTime: patch.digestTime || cfg.DEFAULT_DIGEST_TIME,
    timezone: patch.timezone || cfg.DEFAULT_TIMEZONE,
    createdBy: patch.createdBy || "",
    updatedAt: new Date(),
  });
  const col = await collection("subscriptions");
  if (!col) {
    const key = subKey(id, s);
    mem.subscriptions.set(key, { ...(mem.subscriptions.get(key) || { createdAt: new Date() }), ...doc });
    return mem.subscriptions.get(key);
  }
  try {
    await col.updateOne({ chatId: id, symbol: s }, { $setOnInsert: { createdAt: new Date() }, $set: doc }, { upsert: true });
    return await col.findOne({ chatId: id, symbol: s });
  } catch (err) {
    log.error("db write failed", { collection: "subscriptions", operation: "updateOne", err: safeErr(err) });
    return null;
  }
}

export async function getSubscriptions(chatId) {
  const id = String(chatId);
  const col = await collection("subscriptions");
  if (!col) return [...mem.subscriptions.values()].filter((s) => s.chatId === id && s.status !== "removed");
  try {
    return await col.find({ chatId: id, status: { $ne: "removed" } }).sort({ symbol: 1 }).toArray();
  } catch (err) {
    log.error("db read failed", { collection: "subscriptions", operation: "find", err: safeErr(err) });
    return [];
  }
}

export async function getActiveSubscriptions() {
  const col = await collection("subscriptions");
  if (!col) return [...mem.subscriptions.values()].filter((s) => s.status === "active");
  try {
    return await col.find({ status: "active" }).toArray();
  } catch (err) {
    log.error("db read failed", { collection: "subscriptions", operation: "find", err: safeErr(err) });
    return [];
  }
}

export async function removeSubscription(chatId, symbol) {
  return upsertSubscription(chatId, symbol, { status: "removed" });
}

export async function saveSnapshot(snapshot) {
  const doc = { ...snapshot, symbol: normalizeSymbol(snapshot.symbol), ts: snapshot.ts || new Date() };
  const col = await collection("marketsnapshots");
  if (!col) {
    mem.marketsnapshots.push(doc);
    if (mem.marketsnapshots.length > 5000) mem.marketsnapshots.shift();
    return;
  }
  try {
    await col.insertOne(doc);
  } catch (err) {
    log.error("db write failed", { collection: "marketsnapshots", operation: "insertOne", err: safeErr(err) });
  }
}

export async function getLatestSnapshot(symbol) {
  const s = normalizeSymbol(symbol);
  const col = await collection("marketsnapshots");
  if (!col) return mem.marketsnapshots.filter((x) => x.symbol === s).at(-1) || null;
  try {
    return await col.find({ symbol: s }).sort({ ts: -1 }).limit(1).next();
  } catch (err) {
    log.error("db read failed", { collection: "marketsnapshots", operation: "find", err: safeErr(err) });
    return null;
  }
}

export async function saveDigestRun(run) {
  const doc = cleanMutable({ ...run, createdAt: undefined, updatedAt: new Date() });
  const col = await collection("digestruns");
  if (!col) {
    if (mem.digestruns.has(run.dedupeKey)) return false;
    mem.digestruns.set(run.dedupeKey, { ...run, createdAt: new Date(), updatedAt: new Date() });
    return true;
  }
  try {
    const res = await col.updateOne(
      { dedupeKey: run.dedupeKey },
      { $setOnInsert: { createdAt: new Date() }, $set: doc },
      { upsert: true }
    );
    return Boolean(res.upsertedCount);
  } catch (err) {
    log.error("db write failed", { collection: "digestruns", operation: "updateOne", err: safeErr(err) });
    return false;
  }
}

export async function saveXPost(post) {
  const doc = cleanMutable({ ...post, symbol: normalizeSymbol(post.symbol), updatedAt: new Date() });
  const col = await collection("xposts");
  if (!col) {
    if (mem.xposts.has(post.postId)) return false;
    mem.xposts.set(post.postId, { ...doc, createdAt: new Date() });
    return true;
  }
  try {
    const res = await col.updateOne(
      { postId: post.postId },
      { $setOnInsert: { createdAt: new Date() }, $set: doc },
      { upsert: true }
    );
    return Boolean(res.upsertedCount);
  } catch (err) {
    log.error("db write failed", { collection: "xposts", operation: "updateOne", err: safeErr(err) });
    return false;
  }
}

export async function getRecentXPosts(symbol, limit = 5) {
  const s = normalizeSymbol(symbol);
  const col = await collection("xposts");
  if (!col) return [...mem.xposts.values()].filter((p) => p.symbol === s).slice(-limit).reverse();
  try {
    return await col.find({ symbol: s }).sort({ postTs: -1, createdAt: -1 }).limit(limit).toArray();
  } catch (err) {
    log.error("db read failed", { collection: "xposts", operation: "find", err: safeErr(err) });
    return [];
  }
}

export async function getCursor(handle) {
  const h = String(handle || "").toLowerCase();
  const col = await collection("x_cursors");
  if (!col) return mem.x_cursors.get(h) || null;
  try {
    return await col.findOne({ handle: h });
  } catch (err) {
    log.error("db read failed", { collection: "x_cursors", operation: "findOne", err: safeErr(err) });
    return null;
  }
}

export async function setCursor(handle, lastSeenPostId) {
  const h = String(handle || "").toLowerCase();
  const doc = { handle: h, lastSeenPostId: String(lastSeenPostId || ""), updatedAt: new Date() };
  const col = await collection("x_cursors");
  if (!col) {
    mem.x_cursors.set(h, { ...(mem.x_cursors.get(h) || { createdAt: new Date() }), ...doc });
    return;
  }
  try {
    await col.updateOne({ handle: h }, { $setOnInsert: { createdAt: new Date() }, $set: doc }, { upsert: true });
  } catch (err) {
    log.error("db write failed", { collection: "x_cursors", operation: "updateOne", err: safeErr(err) });
  }
}

